// 필드 정규화 + 규칙기반 상담 분석 (외부 API 없음 · admin.js aiSummary 이식)
const b = $json.body || $json;
const works = Array.isArray(b.works) ? b.works
  : (b.works ? String(b.works).split(/[,·]/).map(s => s.trim()).filter(Boolean) : []);
const d = {
  leadId: 'INQ-' + Date.now(),
  source: b.source || 'website',
  submittedAt: b.submittedAt || new Date().toISOString(),
  name: (b.name || '').toString().trim(),
  phone: (b.phone || '').toString().trim(),
  type: (b.type || '').toString().trim(),
  region: (b.region || '').toString().trim(),
  area: Number(b.area) || null,
  scope: (b.scope || '').toString().trim(),
  works: works.join(', '),
  budget: (b.budget || '').toString().trim(),
  movein: (b.movein || '').toString().trim(),
  live: (b.live || '').toString().trim(),
  memo: (b.memo || '').toString().trim(),
  estimateHint: (b.estimateHint || '').toString().trim(),
  selectedDesign: (b.selectedDesign || '').toString().trim(),
  consent: b.consent === true
};

// 한 줄 요약
const parts = [];
if (d.region) parts.push(d.region);
if (d.area) parts.push(d.area + '평');
parts.push(d.type + (d.scope ? ' ' + d.scope + '공사' : ''));
if (d.budget) parts.push(d.budget);
if (d.movein) parts.push(d.movein + ' 희망');
const summary = parts.filter(Boolean).join(', ');

// 추가 확인 질문 (규칙)
const q = [];
if (d.type !== '상업' && !works.includes('샷시')) q.push('샷시 교체 여부');
if (!works.includes('확장')) q.push('확장 계획');
if (d.type === '주거') q.push('욕실 개수');
if (d.live === '거주중') q.push('거주공사 가능 여부');

// 우선순위 점수 (급함 + 예산 + 규모)
let score = 50;
if (/1개월/.test(d.movein)) score += 20;
if (/5천|8천|이상/.test(d.budget)) score += 15;
if (d.scope === '전체' || d.scope === '전체공사') score += 10;
if ((d.area || 0) >= 30) score += 5;
score = Math.min(score, 98);
const priority = score >= 80 ? '높음' : (score >= 65 ? '보통' : '낮음');

// 공사 분류 · 예산 적합성 (규칙)
const workType = d.type === '상업' ? '상업공간'
  : (d.scope.indexOf('부분') >= 0 ? '부분시공' : '주거전체');
let budgetFit = '확인필요';
if (/8천|이상/.test(d.budget)) budgetFit = '적합';
else if (/^~?3천|3천만원 이하/.test(d.budget) && (d.area || 0) >= 30 && d.scope.indexOf('부분') < 0) budgetFit = '부족가능';

return [{ json: { ...d,
  ai: { summary, questions: q.slice(0, 3), score, priority, workType, budgetFit } } }];
